ls */*_filter_* | perl -ne 'BEGIN{%h=();%s=();}$_=~/(\S+)\//;$n=$1;$s{$n}=1;$_=~/_filter_(up|down)\S+/;$d=$1;open IN,"$_";while(<IN>){chomp;@line=split(/\t/);next if(/^cluster\s+/);$h{$line[0]}{$n}{$d}++;}close IN;END{print "cluster";foreach $n(sort keys %s){print "\t",$n," \(up\)","\t","$n \(down\)";}print "\n";foreach $c(sort {$a<=>$b} keys %h){print "$c";foreach $n(sort keys %s){$h{$c}{$n}{"up"}=0 if not defined($h{$c}{$n}{"up"});$h{$c}{$n}{"down"}=0 if not defined($h{$c}{$n}{"down"});print "\t",$h{$c}{$n}{"up"},"\t",$h{$c}{$n}{"down"};}print "\n";}}' > deg_stat.xls
Rscript /Users/chengchao/biosource/besaltgraphic/bioplot/apps/bar_deg.r -f deg_stat.xls -p ci